args.ReplacementContent:
"let rawSupabaseUrl = import.meta.env.VITE_SUPABASE_URL || '';
rawSupabaseUrl = rawSupabaseUrl.replace(/\/$/, ''); // Remove trailing slash
rawSupabaseUrl = rawSupabaseUrl.replace(/\/rest\/v1$/, ''); // Remove /rest/v1 if present
rawSupabaseUrl = rawSupabaseUrl.replace(/\/auth\/v1$/, ''); // Remove /auth/v1 if present

const anonSupabase = createClient(
  rawSupabaseUrl,
  import.meta.env.VITE_SUPABASE_ANON_KEY || '',
  {
    auth: {
      persistSession: false,
      autoRefreshToken: false,
      detectSessionInUrl: false
    }
  }
);"

